#include <ctype.h>

static int precedence(char op) {
    if (op == '^') return 3;
    if (op == '*' || op == '/') return 2;
    if (op == '+' || op == '-') return 1;
    return 0;
}

static int right_associative(char op) {
    return op == '^';
}

char *infix_to_postfix(const char *expression) {
    static char output[10000];
    char stack[10000];
    int out = 0;
    int top = -1;

    for (int i = 0; expression[i] != '\0'; i++) {
        char ch = expression[i];
        if (isspace((unsigned char)ch)) {
            continue;
        }
        if (isalnum((unsigned char)ch)) {
            output[out++] = ch;
        } else if (ch == '(') {
            stack[++top] = ch;
        } else if (ch == ')') {
            while (top >= 0 && stack[top] != '(') {
                output[out++] = stack[top--];
            }
            if (top >= 0 && stack[top] == '(') {
                top--;
            }
        } else {
            while (
                top >= 0 &&
                stack[top] != '(' &&
                (
                    precedence(stack[top]) > precedence(ch) ||
                    (
                        precedence(stack[top]) == precedence(ch) &&
                        !right_associative(ch)
                    )
                )
            ) {
                output[out++] = stack[top--];
            }
            stack[++top] = ch;
        }
    }

    while (top >= 0) {
        if (stack[top] != '(') {
            output[out++] = stack[top];
        }
        top--;
    }

    output[out] = '\0';
    return output;
}

#include <cctype>
#include <stack>
#include <string>

namespace {
int precedence(char op) {
    if (op == '^') {
        return 3;
    }
    if (op == '*' || op == '/') {
        return 2;
    }
    if (op == '+' || op == '-') {
        return 1;
    }
    return 0;
}

bool is_right_associative(char op) {
    return op == '^';
}
}  // namespace

std::string infix_to_postfix(const std::string& expression) {
    std::string output;
    std::stack<char> operators;

    for (char token : expression) {
        if (std::isalnum(static_cast<unsigned char>(token))) {
            output.push_back(token);
            continue;
        }

        if (token == '(' || token == '[' || token == '{') {
            operators.push(token);
            continue;
        }

        if (token == ')' || token == ']' || token == '}') {
            char opening = token == ')' ? '(' : (token == ']' ? '[' : '{');
            while (!operators.empty() && operators.top() != opening) {
                output.push_back(operators.top());
                operators.pop();
            }
            if (!operators.empty()) {
                operators.pop();
            }
            continue;
        }

        while (!operators.empty()) {
            char top = operators.top();
            if (top == '(' || top == '[' || top == '{') {
                break;
            }

            int top_precedence = precedence(top);
            int current_precedence = precedence(token);
            bool should_pop = top_precedence > current_precedence;
            if (!is_right_associative(token) && top_precedence == current_precedence) {
                should_pop = true;
            }
            if (!should_pop) {
                break;
            }

            output.push_back(top);
            operators.pop();
        }

        operators.push(token);
    }

    while (!operators.empty()) {
        output.push_back(operators.top());
        operators.pop();
    }

    return output;
}

import java.util.ArrayDeque;
import java.util.Deque;

public class InfixToPostfix {
    public static String infixToPostfix(String expression) {
        StringBuilder output = new StringBuilder();
        Deque<Character> stack = new ArrayDeque<>();

        for (int i = 0; i < expression.length(); i++) {
            char ch = expression.charAt(i);
            if (Character.isLetterOrDigit(ch)) {
                output.append(ch);
            } else if (ch == '(') {
                stack.push(ch);
            } else if (ch == ')') {
                while (!stack.isEmpty() && stack.peek() != '(') {
                    output.append(stack.pop());
                }
                if (!stack.isEmpty() && stack.peek() == '(') {
                    stack.pop();
                }
            } else {
                while (!stack.isEmpty() && stack.peek() != '(') {
                    char top = stack.peek();
                    int topPrecedence = precedence(top);
                    int currentPrecedence = precedence(ch);
                    if (topPrecedence > currentPrecedence || (topPrecedence == currentPrecedence && ch != '^')) {
                        output.append(stack.pop());
                    } else {
                        break;
                    }
                }
                stack.push(ch);
            }
        }

        while (!stack.isEmpty()) {
            char ch = stack.pop();
            if (ch != '(') {
                output.append(ch);
            }
        }

        return output.toString();
    }

    private static int precedence(char operator) {
        switch (operator) {
            case '^':
                return 3;
            case '*':
            case '/':
                return 2;
            case '+':
            case '-':
                return 1;
            default:
                return 0;
        }
    }
}

fun infixToPostfix(expression: String): String {
    if (expression.isEmpty()) {
        return ""
    }

    fun precedence(ch: Char): Int = when (ch) {
        '^' -> 3
        '*', '/' -> 2
        '+', '-' -> 1
        else -> 0
    }

    fun isRightAssociative(ch: Char): Boolean = ch == '^'

    val output = StringBuilder()
    val operators = ArrayDeque<Char>()

    for (ch in expression) {
        when {
            ch.isLetterOrDigit() -> output.append(ch)
            ch == '(' -> operators.addLast(ch)
            ch == ')' -> {
                while (operators.isNotEmpty() && operators.last() != '(') {
                    output.append(operators.removeLast())
                }
                if (operators.isNotEmpty() && operators.last() == '(') {
                    operators.removeLast()
                }
            }
            else -> {
                while (
                    operators.isNotEmpty() &&
                    operators.last() != '(' &&
                    (
                        precedence(operators.last()) > precedence(ch) ||
                            (
                                precedence(operators.last()) == precedence(ch) &&
                                    !isRightAssociative(ch)
                                )
                        )
                ) {
                    output.append(operators.removeLast())
                }
                operators.addLast(ch)
            }
        }
    }

    while (operators.isNotEmpty()) {
        val op = operators.removeLast()
        if (op != '(') {
            output.append(op)
        }
    }

    return output.toString()
}

import Foundation

func infixToPostfix(_ expression: String) -> String {
    func precedence(_ op: Character) -> Int {
        switch op {
        case "^": return 3
        case "*", "/": return 2
        case "+", "-": return 1
        default: return 0
        }
    }

    func isRightAssociative(_ op: Character) -> Bool {
        op == "^"
    }

    var output = ""
    var stack: [Character] = []

    for ch in expression {
        if ch.isLetter || ch.isNumber {
            output.append(ch)
        } else if ch == "(" {
            stack.append(ch)
        } else if ch == ")" {
            while let top = stack.last, top != "(" {
                output.append(stack.removeLast())
            }
            if stack.last == "(" {
                stack.removeLast()
            }
        } else {
            while let top = stack.last, top != "(" {
                let topPrecedence = precedence(top)
                let currentPrecedence = precedence(ch)
                if topPrecedence > currentPrecedence || (topPrecedence == currentPrecedence && !isRightAssociative(ch)) {
                    output.append(stack.removeLast())
                } else {
                    break
                }
            }
            stack.append(ch)
        }
    }

    while let top = stack.popLast() {
        if top != "(" {
            output.append(top)
        }
    }

    return output
}
